using UnityEngine;

/// <summary>
/// Faz o GameObject girar continuamente (add-on opcional — ex: plataforma
/// giratória, hélice, obstáculo rotativo). Combina com MovingPlatform se a
/// plataforma também se deslocar.
/// </summary>
[DisallowMultipleComponent]
public class PlatformSpinner : MonoBehaviour
{
    [Tooltip("Velocidade de rotação em graus/segundo.")]
    public float grausPorSegundo = 90f;

    [Tooltip("Ligado = sentido horário. Desligado = anti-horário.")]
    public bool sentidoHorario = true;

    private void Update()
    {
        float sign = sentidoHorario ? -1f : 1f;
        transform.Rotate(0f, 0f, grausPorSegundo * sign * Time.deltaTime);
    }
}
